function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}

function randomId() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// Get all existing hashes and their states from the sheet
const sheetRows = $input.all();
const existingItems = {};
sheetRows.forEach(row => {
  if (row.json.source_hash) {
    existingItems[row.json.source_hash] = row.json.state || '';
  }
});

// Get RSS items from the HTTP/XML nodes
const rssData = $('XML').first().json;
const channel = rssData.rss.channel;
const items = Array.isArray(channel.item) ? channel.item : [channel.item];

return items.slice(0, 5).map(item => {
  const url = typeof item.link === 'object' ? item.link._ || '' : item.link || '';
  const pubDate = item.pubDate || '';
  const normalized = url.trim().toLowerCase();
  const hash = simpleHash(normalized + pubDate);

  // Skip if already in a non-NEW terminal state
  const existingState = existingItems[hash] || '';
  const isNew = !existingState;

  return {
    json: {
      source_hash: hash,
      source_url: url,
      source_title: item.title || '',
      source_published_at: pubDate,
      correlation_id: randomId(),
      created_at: new Date().toISOString(),
      is_new: isNew,
      existing_state: existingState
    }
  };
});

return $input.all().map(item => {
  const title = item.json.source_title || '';
  const url = item.json.source_url || '';
  const pubDate = item.json.source_published_at || '';
  const sourceHash = item.json.source_hash || '';
  const correlationId = item.json.correlation_id || '';

  // Normalize title
  const cleanTitle = title
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 200);

  // Build prompt-ready content block
  const contentBlock = `Title: ${cleanTitle}\nPublished: ${pubDate}\nURL: ${url}`;

  return {
    json: {
      ...item.json,
      preprocessed_content: contentBlock,
      state: 'PREPROCESSED',
      updated_at: new Date().toISOString()
    }
  };
});

return $input.all().map(item => {
  const content = item.json.preprocessed_content;

  const body = {
    model: "gpt-4o-mini",
    max_tokens: 1000,
    messages: [
      {
        role: "system",
        content: "You are a content repurposing assistant. Given an article title and metadata, generate multi-channel marketing content. You must respond with valid JSON only. No prose, no markdown, no code fences. Only the JSON object."
      },
      {
        role: "user",
        content: `${content}\n\nRespond with a JSON object containing exactly these fields:\n{\n  "twitter_thread": ["tweet 1", "tweet 2", "tweet 3"],\n  "linkedin_post": "string, max 1300 chars",\n  "newsletter": "string, max 500 chars",\n  "title_options": ["option 1", "option 2", "option 3"],\n  "hashtags": ["tag1", "tag2", "tag3", "tag4", "tag5"]\n}`
      }
    ]
  };

  return {
    json: {
      ...item.json,
      request_body: body
    }
  };
});

const REQUIRED_FIELDS = ['twitter_thread', 'linkedin_post', 'newsletter', 'title_options', 'hashtags'];

return $input.all().map(item => {
  const raw = item.json.choices?.[0]?.message?.content || '';
  let parsed = null;
  let validationStatus = 'INVALID';
  let lastError = '';

  // Parse
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    lastError = `JSON parse failed: ${e.message}`;
    return {
      json: {
        ...item.json,
        llm_output_raw: raw,
        validation_status: 'INVALID',
        last_error: lastError,
        state: 'FAILED_LLM',
        updated_at: new Date().toISOString()
      }
    };
  }

  // Validate required fields
  const missingFields = REQUIRED_FIELDS.filter(f => !(f in parsed));
  if (missingFields.length > 0) {
    lastError = `Missing fields: ${missingFields.join(', ')}`;
    return {
      json: {
        ...item.json,
        llm_output_raw: raw,
        validation_status: 'INVALID',
        last_error: lastError,
        state: 'FAILED_LLM',
        updated_at: new Date().toISOString()
      }
    };
  }

  // Validate field types
  if (!Array.isArray(parsed.twitter_thread)) lastError += 'twitter_thread must be array. ';
  if (typeof parsed.linkedin_post !== 'string') lastError += 'linkedin_post must be string. ';
  if (typeof parsed.newsletter !== 'string') lastError += 'newsletter must be string. ';
  if (!Array.isArray(parsed.title_options)) lastError += 'title_options must be array. ';
  if (!Array.isArray(parsed.hashtags)) lastError += 'hashtags must be array. ';

  if (lastError) {
    return {
      json: {
        ...item.json,
        llm_output_raw: raw,
        validation_status: 'INVALID',
        last_error: lastError.trim(),
        state: 'FAILED_LLM',
        updated_at: new Date().toISOString()
      }
    };
  }

  // Valid
  return {
    json: {
      ...item.json,
      llm_output_raw: raw,
      twitter_thread: parsed.twitter_thread,
      linkedin_post: parsed.linkedin_post,
      newsletter: parsed.newsletter,
      title_options: parsed.title_options,
      hashtags: parsed.hashtags,
      validation_status: 'VALID',
      last_error: '',
      state: 'GENERATED',
      generation_attempt: (item.json.generation_attempt || 0) + 1,
      updated_at: new Date().toISOString()
    }
  };
});

