return $input.all().map(item => {
  return {
    json: {
      ...item.json,
      state: 'NEW',
      retry_count: 0,
      last_error: '',
      prompt_version: 'v1.0',
      model: 'gpt-4o-mini',
      llm_output_raw: '',
      validation_status: '',
      generation_attempt: 0,
      approval_form_url: '',
      approved_by: '',
      approved_at: '',
      published_at: '',
      draft_destination_url: '',
      updated_at: new Date().toISOString()
    }
  };
});

const MAX_RETRIES = 2;

return $input.all().map(item => {
  // If valid, pass through unchanged
  if (item.json.validation_status === 'VALID') {
    return { json: item.json };
  }

  // Failed item — check retry count
  const retryCount = (item.json.retry_count || 0) + 1;

  if (retryCount > MAX_RETRIES) {
    return {
      json: {
        ...item.json,
        state: 'QUARANTINED',
        retry_count: retryCount,
        last_error: `Quarantined after ${MAX_RETRIES} retries. Last error: ${item.json.last_error}`,
        updated_at: new Date().toISOString()
      }
    };
  }

  return {
    json: {
      ...item.json,
      state: 'FAILED_LLM',
      retry_count: retryCount,
      updated_at: new Date().toISOString()
    }
  };
});
